export default function Services() {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [dragOffset, setDragOffset] = useState(0);
  const [isAnimating, setIsAnimating] = useState(false);
  const dragStartX = useRef(0);
  const sliderRef = useRef<HTMLDivElement>(null);

  // Auto-advance slider every 30 seconds
  // State for tracking drag with timestamps and velocity
  const dragTimeRef = useRef(0);
  const dragVelocityRef = useRef(0);

  // Configuration constants - tunable for flexibility
  const SWIPE_THRESHOLD = 50; // Minimum pixels to trigger slide
  const VELOCITY_THRESHOLD = 0.5; // Pixels per millisecond for swipe velocity
  const ANIMATION_DURATION = 300; // Base milliseconds for snap animation
  const AUTO_ADVANCE_INTERVAL = 10000; // 10 seconds (resets on interaction)
  const CARDS_TO_DISPLAY = 4; // Number of cards visible at once

  // Enhanced useEffect with proper auto-advance that pauses on interaction
  useEffect(() => {
    const timer = setInterval(() => {
      if (!isAnimating) {
        setIsAnimating(true);
        setCurrentIndex((prevIndex) => (prevIndex + 1) % services.length);
        setTimeout(() => {
          setDragOffset(0);
          setIsAnimating(false);
        }, ANIMATION_DURATION);
      }
    }, 10000); // 10 seconds

    return () => clearInterval(timer);
  }, [isAnimating, services.length]);

  // Get visible cards with wrapping
  const getVisibleServices = () => {
    const visibleServices = [];
    for (let i = 0; i < CARDS_TO_DISPLAY; i++) {
      visibleServices.push(services[(currentIndex + i) % services.length]);
    }
    return visibleServices;
  };

  // Handle mouse drag start
  const handleMouseDown = (e: React.MouseEvent) => {
    if (isAnimating) return;
    dragStartX.current = e.clientX;
    dragTimeRef.current = Date.now();
    dragVelocityRef.current = 0;
  };

  // Handle mouse drag move
  const handleMouseMove = (e: React.MouseEvent) => {
    if (dragStartX.current === 0 || isAnimating) return;
    const diff = e.clientX - dragStartX.current;
    setDragOffset(diff);
  };

  // Handle mouse drag end
  const handleMouseUp = (e: React.MouseEvent) => {
    if (dragStartX.current === 0) return;
    const diff = e.clientX - dragStartX.current;
    const timeDiff = Date.now() - dragTimeRef.current;
    dragStartX.current = 0;
    handleDragEnd(diff, timeDiff);
  };

  // Handle mouse leave (cancel drag)
  const handleMouseLeave = (e: React.MouseEvent) => {
    if (dragStartX.current === 0 || isAnimating) return;
    const diff = e.clientX - dragStartX.current;
    const timeDiff = Date.now() - dragTimeRef.current;
    dragStartX.current = 0;
    handleDragEnd(diff, timeDiff);
  };

  // Handle touch start
  const handleTouchStart = (e: React.TouchEvent) => {
    if (isAnimating) return;
    dragStartX.current = e.touches[0].clientX;
    dragTimeRef.current = Date.now();
    dragVelocityRef.current = 0;
  };

  // Handle touch move
  const handleTouchMove = (e: React.TouchEvent) => {
    if (dragStartX.current === 0 || isAnimating) return;
    const diff = e.touches[0].clientX - dragStartX.current;
    setDragOffset(diff);
  };

  // Handle touch end
  const handleTouchEnd = (e: React.TouchEvent) => {
    if (dragStartX.current === 0) return;
    const diff = e.changedTouches[0].clientX - dragStartX.current;
    const timeDiff = Date.now() - dragTimeRef.current;
    dragStartX.current = 0;
    handleDragEnd(diff, timeDiff);
  };

  // Common drag end logic with velocity detection
  const handleDragEnd = (distance: number, timeTaken: number) => {
    const velocity = distance / Math.max(timeTaken, 1); // Pixels per millisecond

    // Determine if slide should happen based on distance OR velocity
    const shouldSlide =
      Math.abs(distance) > SWIPE_THRESHOLD ||
      Math.abs(velocity) > VELOCITY_THRESHOLD;

    if (shouldSlide) {
      setIsAnimating(true);
      if (distance > 0 || velocity > VELOCITY_THRESHOLD) {
        // Swiped right - go to previous
        setCurrentIndex((prevIndex) =>
          prevIndex === 0 ? services.length - 1 : prevIndex - 1
        );
      } else {
        // Swiped left - go to next
        setCurrentIndex((prevIndex) => (prevIndex + 1) % services.length);
      }

      // Use velocity to determine animation duration (faster swipes = faster animation, but capped)
      const velocityAdjustedDuration = Math.max(200, Math.min(ANIMATION_DURATION, ANIMATION_DURATION - Math.abs(velocity) * 100));

      setTimeout(() => {
        setDragOffset(0);
        setIsAnimating(false);
      }, velocityAdjustedDuration);
    } else {
      // Snap back with smooth deceleration
      setDragOffset(0);
    }
  };

  // Keyboard navigation support
  const handleKeyDown = (e: React.KeyboardEvent<HTMLDivElement>) => {
    if (isAnimating) return; // Prevent interaction during animation

    switch (e.key) {
      case 'ArrowRight':
        e.preventDefault();
        setIsAnimating(true);
        setCurrentIndex(prev => (prev + 1) % services.length);
        setTimeout(() => {
          setDragOffset(0);
          setIsAnimating(false);
        }, ANIMATION_DURATION);
        break;
      case 'ArrowLeft':
        e.preventDefault();
        setIsAnimating(true);
        setCurrentIndex(prev => prev === 0 ? services.length - 1 : prev - 1);
        setTimeout(() => {
          setDragOffset(0);
          setIsAnimating(false);
        }, ANIMATION_DURATION);
        break;
      default:
        break;
    }
  };

  // Handle pagination dot click
  const handleDotClick = (index: number) => {
    if (isAnimating || index === currentIndex) return;
    
    setIsAnimating(true);
    setCurrentIndex(index);
    setTimeout(() => {
      setDragOffset(0);
      setIsAnimating(false);
    }, ANIMATION_DURATION);
  };

  return (
    <section id="services" className="py-12 md:py-16">
      <div className="mx-auto w-full max-w-7xl px-4 sm:px-6 lg:px-8">
        {/* Section Title */}
        <SectionTitle title="Our Services" className="mb-5" />

        <p
          className={`text-center text-[28px] leading-[36px] tracking-[-0.02em] font-[400] text-[#1E1E1F] mt-2 mb-8 md:mb-12 ${poppins.className}`}
        >
          We offer a wide range of digital solutions to help your business
          thrive
        </p>

        {/* Services Slider */}
        <div
          className="overflow-hidden cursor-grab active:cursor-grabbing"
          onMouseDown={handleMouseDown}
          onMouseMove={handleMouseMove}
          onMouseUp={handleMouseUp}
          onMouseLeave={handleMouseUp}
          onTouchStart={handleTouchStart}
          onTouchMove={handleTouchMove}
          onTouchEnd={handleTouchEnd}
          onKeyDown={handleKeyDown}
          ref={sliderRef}
          role="region"
          aria-label="Services carousel"
          aria-live="polite"
          aria-atomic="false"
          tabIndex={0}
        >
          <div
            className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-0"
            style={{
              transform: `translateX(${dragOffset}px)`,
              transition: isAnimating ? 'transform 0.3s ease-out' : 'none',
            }}
          >
            {getVisibleServices().map((service, index) => (
              <div
                key={`${service.title}-${currentIndex}`}
                className="h-full"
                draggable={false}
              >
                <ServiceCard
                  title={service.title}
                  iconLabel={service.iconLabel}
                  svg={service.svg}
                />
              </div>
            ))}
          </div>
        </div>

        {/* Pagination Indicators */}
        <div className="flex justify-center gap-2 mt-6 mb-4">
          {services.map((_, index) => (
            <button
              key={index}
              onClick={() => handleDotClick(index)}
              className={`inline-block h-2 rounded-full transition-all duration-300 ${
                index === currentIndex
                  ? 'bg-[#65C59D] w-8'
                  : 'bg-[#E0E0E0] w-2 hover:bg-[#65C59D]'
              }`}
              aria-label={`Go to service ${index + 1}`}
              aria-current={index === currentIndex ? 'page' : undefined}
              disabled={isAnimating}
            />
          ))}
        </div>

        {/* Show All Button */}
        <div className="flex justify-center mt-8">
          <div className="mt-6 md:mt-8">
            <Button
              variant="primary"
              href="/services"
              showArrow={false}
              className="w-[210px] h-[44px] px-6 py-[10px] !rounded-[12px] justify-center bg-[#65C59D] hover:bg-[#65C59D] border-0 hover:border-0 text-[16px]"
            >
              <span>Show All Services</span>
              <svg
                width="15"
                height="23"
                viewBox="0 0 15 23"
                fill="none"
                xmlns="http://www.w3.org/2000/svg"
                aria-hidden="true"
              >
                <path
                  d="M2.86621 0.834961C2.51324 0.830097 2.16647 0.925461 1.86816 1.1084L1.84863 1.12012L1.82812 1.13086C1.502 1.30708 1.23696 1.57264 1.0625 1.89258C0.888072 2.21253 0.811487 2.57495 0.841797 2.93555L0.84375 2.9541V2.97266C0.865847 3.54835 0.935514 4.31459 0.935547 4.98828V4.99121C0.934532 5.34643 1.0317 5.6959 1.21777 6.00195C1.40388 6.308 1.67169 6.55992 1.99414 6.72852L2.0127 6.7373L2.0293 6.74805C3.4988 7.60892 4.97365 8.48282 6.45312 9.37012C7.04441 9.72422 7.64382 10.102 8.31934 10.5156L10.8467 12.0625H8.14941C7.96289 12.2094 7.80025 12.3392 7.63184 12.4639C5.88842 13.7543 4.10948 15.0863 2.32617 16.3477L2.29883 16.3652C1.99134 16.5652 1.74569 16.8435 1.58691 17.168C1.42835 17.4922 1.36249 17.8525 1.39453 18.21L1.39551 18.2197V18.2305C1.41903 18.5967 1.43139 18.9641 1.44434 19.3096C1.45748 19.6604 1.47173 19.9949 1.5 20.3252L1.50098 20.3369L1.51367 20.4766C1.55168 20.7752 1.66055 21.062 1.83301 21.3135C2.03006 21.6009 2.30292 21.8317 2.62402 21.9805C2.94543 22.1292 3.30293 22.1899 3.65723 22.1553C4.01125 22.1206 4.34827 21.9925 4.63281 21.7852L4.63965 21.7803L6.52051 20.4287C8.40166 19.0705 10.2838 17.692 12.166 16.2988L12.1719 16.2939L12.3555 16.1533C12.7729 15.8127 13.1179 15.3938 13.3701 14.9209C13.6223 14.448 13.7763 13.9313 13.8242 13.4014L13.8379 13.1738C13.8635 11.9553 13.8255 10.7362 13.7246 9.52148L13.7227 9.49609L13.7217 9.4707C13.7051 8.72473 13.4985 7.99434 13.1201 7.34668C12.7417 6.69901 12.2041 6.15381 11.5547 5.76367H11.5537L11.5498 5.76074C9.01624 4.21597 6.44727 2.68671 3.88281 1.15332L3.86816 1.14453L3.85449 1.13574C3.5618 0.944953 3.21891 0.839904 2.86621 0.834961Z"
                  stroke="white"
                  strokeWidth="1.67"
                />
              </svg>
            </Button>
          </div>
        </div>
      </div>
    </section>
  );
}
